// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}

function useComponent(props: Props) {
  const { city, temperature, condition, humidity, windSpeed, unit, forecast } = props;

  const getConditionIcon = useCallback((cond: string) => {
    const c = cond.toLowerCase();
    if (c.includes('sun')) return 'sun'; // Replace with cloud/sun icon names if available
    if (c.includes('cloud')) return 'cloud';
    if (c.includes('rain')) return 'cloud-rain'; // Using supported icon names
    return 'sun';
  }, []);

  return { city, temperature, condition, humidity, windSpeed, unit, forecast, getConditionIcon };
}

export default function Component(props: Props) {
  const { city, temperature, condition, humidity, windSpeed, unit, forecast, getConditionIcon } = useComponent(props);

  return (
    <Card padding={24} radius="lg" shadow="md">
      <Stack gap={16}>
        <Row justify="between" align="center">
          <Heading level={3}>{city}</Heading>
          <Badge variant="primary">{condition}</Badge>
        </Row>
        <Stack align="center" gap={8}>
          <Icon name={getConditionIcon(condition)} size={48} color="var(--ggui-color-primary-600, #0284c7)" />
          <Heading level={1}>{temperature}°{unit}</Heading>
        </Stack>
        <Row justify="center" gap={24}>
          <Box><Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text><Text>{humidity}%</Text></Box>
          <Box><Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind</Text><Text>{windSpeed} km/h</Text></Box>
        </Row>
        <Divider margin={16} />
        <Row justify="between">
          {forecast.slice(0, 5).map((f, i) => (
            <Box as={Hoverable} key={i} padding={8} borderRadius={8} hoverStyle={{ background: 'var(--ggui-color-surfaceVariant, #f4f4f5)' }}>
              <Stack align="center" gap={4}>
                <Text variant="caption">{f.day}</Text>
                <Icon name={getConditionIcon(f.icon || '')} size={24} color="var(--ggui-color-primary-600, #0284c7)" />
                <Text variant="bodySmall">{f.high}°/{f.low}°</Text>
              </Stack>
            </Box>
          ))}
        </Row>
      </Stack>
    </Card>
  );
}

