import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
  onTaskUpdate?: (data: Record<string, unknown>) => void; // Action: Task Updated
}

function useComponent(props: Props) {
  const handleTaskUpdate = useCallback((data: Record<string, unknown>) => {
    props.onTaskUpdate?.(data);
  }, [props.onTaskUpdate]);

  const [tasks, setTasks] = useState(props.tasks || []);

  const tasksByColumn = useMemo(() => {
    return (props.columns || []).reduce((acc, col) => {
      acc[col.id!] = tasks.filter(t => t.column === col.id);
      return acc;
    }, {} as Record<string, typeof tasks>);
  }, [tasks, props.columns]);

  const summary = useMemo(() => {
    const total = tasks.length;
    const doneCol = (props.columns || []).find(c => c.name?.toLowerCase().includes('done'))?.id;
    const completed = tasks.filter(t => t.column === doneCol).length;
    return { total, completed };
  }, [tasks, props.columns]);

  const moveTask = useCallback((taskId: string, newColumn: string) => {
    const updatedTasks = tasks.map(t => t.id === taskId ? { ...t, column: newColumn } : t);
    setTasks(updatedTasks);
    handleTaskUpdate({ taskId, column: newColumn, type: 'MOVE' });
  }, [tasks, handleTaskUpdate]);

  const addTask = useCallback((columnId: string, title: string, priority: 'low' | 'medium' | 'high', dueDate?: string) => {
    const newTask = { id: Math.random().toString(36).substr(2, 9), title, priority, column: columnId, assignee: '??', dueDate };
    setTasks([...tasks, newTask]);
    handleTaskUpdate({ task: newTask, type: 'CREATE' });
  }, [tasks, handleTaskUpdate]);

  const editTask = useCallback((taskId: string, title: string) => {
    const updatedTasks = tasks.map(t => t.id === taskId ? { ...t, title } : t);
    setTasks(updatedTasks);
    handleTaskUpdate({ taskId, title, type: 'UPDATE' });
  }, [tasks, handleTaskUpdate]);

  return { tasksByColumn, summary, moveTask, addTask, editTask };
}

export default function Component(props: Props) {
  const { tasksByColumn, summary, moveTask, addTask, editTask } = useComponent(props);
  const [addingTo, setAddingTo] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editTitle, setEditTitle] = useState('');
  const [newTaskDueDate, setNewTaskDueDate] = useState('');

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={16}>
        <Row justify="between" align="center">
          <Heading level={2}>Project Board</Heading>
          <Stack direction="horizontal" gap={16}>
            <Badge variant="primary">Total: {summary.total}</Badge>
            <Badge variant="success">Done: {summary.completed}</Badge>
          </Stack>
        </Row>
        <Row gap={16} align="start">
          {(props.columns || []).map(col => (
            <Box key={col.id} style={{ flex: 1 }}>
              <Card padding={16} radius="lg" style={{ background: 'var(--ggui-color-surfaceVariant, #f4f4f5)' }}>
                <Stack gap={12}>
                  <Row justify="between" align="center">
                    <Heading level={4}>{col.name}</Heading>
                    <Badge variant="secondary">{tasksByColumn[col.id!]?.length || 0}</Badge>
                  </Row>
                  <Stack gap={8}>
                    {tasksByColumn[col.id!]?.map(task => (
                      <Card key={task.id} shadow="sm" padding={12} radius="md">
                        <Stack gap={8}>
                          {editingId === task.id ? (
                            <Stack gap={8}>
                              <Input value={editTitle} onChange={setEditTitle} autoFocus />
                              <Row gap={8}>
                                <Button size="xs" onClick={() => { editTask(task.id!, editTitle); setEditingId(null); }}>Save</Button>
                                <Button size="xs" variant="ghost" onClick={() => setEditingId(null)}>Cancel</Button>
                              </Row>
                            </Stack>
                          ) : (
                            <Row justify="between" align="center">
                              <Text variant="body" weight="medium">{task.title}</Text>
                              <Button size="xs" variant="ghost" onClick={() => { setEditingId(task.id!); setEditTitle(task.title!); }}>Edit</Button>
                            </Row>
                          )}
                          <Row justify="between" align="center">
                            <Badge variant={task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'warning' : 'default'}>{task.priority}</Badge>
                            {task.dueDate && <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Due: {task.dueDate}</Text>}
                            <Avatar name={task.assignee || '??'} size={24} />
                          </Row>
                          <Dropdown
                            trigger={<Button variant="outline" size="xs">Move</Button>}
                            value=""
                            onChange={(newCol) => moveTask(task.id!, newCol)}
                            options={(props.columns || []).map(c => ({ value: c.id!, label: `Move to ${c.name}` }))}
                          />
                        </Stack>
                      </Card>
                    ))}
                  </Stack>
                  {addingTo === col.id ? (
                    <Stack gap={8}>
                      <Input placeholder="Task title..." value={newTaskTitle} onChange={setNewTaskTitle} autoFocus />
                      <Select 
                        value={newTaskPriority} 
                        onChange={(v) => setNewTaskPriority(v as any)}
                        options={[{value: 'low', label: 'Low'}, {value: 'medium', label: 'Medium'}, {value: 'high', label: 'High'}]}
                      />
                      <Input type="date" value={newTaskDueDate} onChange={setNewTaskDueDate} />
                      <Row gap={8}>
                        <Button size="sm" onClick={() => { addTask(col.id!, newTaskTitle || 'New Task', newTaskPriority, newTaskDueDate); setAddingTo(null); setNewTaskTitle(''); setNewTaskDueDate(''); }}>Add</Button>
                        <Button variant="ghost" size="sm" onClick={() => setAddingTo(null)}>Cancel</Button>
                      </Row>
                    </Stack>
                  ) : (
                    <Button variant="ghost" size="sm" onClick={() => setAddingTo(col.id!)}>+ Add Task</Button>
                  )}
                </Stack>
              </Card>
            </Box>
          ))}
        </Row>
      </Stack>
    </Container>
  );
}

