import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}

function useComponent(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selected, setSelected] = useState<Props['elements'][0] | null>(null);

  const filteredElements = useMemo(() => {
    const q = searchQuery.toLowerCase();
    return props.elements.filter(
      (el) =>
        el.name?.toLowerCase().includes(q) || el.symbol?.toLowerCase().includes(q)
    );
  }, [props.elements, searchQuery]);

  const categories = useMemo(() => Array.from(new Set(props.elements.map((e) => e.category))), [props.elements]);

  const getCategoryColor = (cat?: string) => {
    const map: Record<string, string> = {
      'noble-gas': 'var(--ggui-color-info-300)',
      'halogen': 'var(--ggui-color-warning-300)',
      'alkali-metal': 'var(--ggui-color-error-300)',
      'alkaline-earth-metal': 'var(--ggui-color-success-300)',
      'transition-metal': 'var(--ggui-color-primary-300)',
      'lanthanide': 'var(--ggui-color-container)',
      'actinide': 'var(--ggui-color-container)',
      'post-transition-metal': 'var(--ggui-color-outlineVariant)',
      'metalloid': 'var(--ggui-color-outline)',
      'reactive-nonmetal': 'var(--ggui-color-neutral-200)',
    };
    return map[cat || ''] || 'var(--ggui-color-surfaceVariant)';
  };

  return { searchQuery, setSearchQuery, selected, setSelected, filteredElements, categories, getCategoryColor };
}

export default function Component(props: Props) {
  const { searchQuery, setSearchQuery, selected, setSelected, filteredElements, categories, getCategoryColor } = useComponent(props);

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={24}>
        <Heading level={1}>Periodic Table</Heading>
        <SearchField value={searchQuery} onChange={setSearchQuery} placeholder="Search by name or symbol..." />

        <Box role="grid" style={{ display: 'grid', gridTemplateColumns: 'repeat(18, minmax(48px, 1fr))', gridAutoRows: '64px', gap: 'var(--ggui-spacing-1, 4px)', padding: 'var(--ggui-spacing-2, 8px) 0', overflowX: 'auto' }}>
          {props.elements.map((el) => (
            <Card 
              key={el.symbol} 
              as={Clickable} 
              onPress={() => setSelected(el)}
              border={true}
              aria-label={`${el.name}, atomic number ${el.atomicNumber}`}
              style={{ 
                gridColumn: `${el.col}`, 
                gridRow: `${el.row}`, 
                backgroundColor: getCategoryColor(el.category),
                opacity: !searchQuery || filteredElements.includes(el) ? 1 : 0.2,
                transition: 'all 200ms ease',
                borderColor: selected?.symbol === el.symbol ? 'var(--ggui-color-primary-600)' : 'transparent',
                borderWidth: selected?.symbol === el.symbol ? '2px' : '1px',
                cursor: 'pointer'
              }}
            >
              <Stack align="center" justify="center" gap={0} style={{ height: '100%', pointerEvents: 'none' }}>
                <Text variant="caption" size="xs" color="var(--ggui-color-onSurface)" style={{ opacity: 0.7 }}>{el.atomicNumber}</Text>
                <Text variant="body" weight="bold" color="var(--ggui-color-onSurface)">{el.symbol}</Text>
              </Stack>
            </Card>
          ))}
        </Box>

        <Box padding={16} background="var(--ggui-color-surfaceVariant)" borderRadius="md">
          <Stack direction="horizontal" gap={16} wrap>
            <Text weight="semibold">Legend:</Text>
            {categories.filter((cat): cat is string => !!cat).map(cat => (
              <Stack key={cat} direction="horizontal" align="center" gap={8}>
                <Box style={{ width: 14, height: 14, backgroundColor: getCategoryColor(cat), borderRadius: 4, border: '1px solid var(--ggui-color-outlineVariant)' }} />
                <Text variant="caption" style={{ textTransform: 'capitalize' }}>{cat?.replace('-', ' ')}</Text>
              </Stack>
            ))}
          </Stack>
        </Box>
        {selected && (
          <Card padding={24} style={{ position: 'sticky', bottom: 0, zIndex: 1000 }}>
            <Stack gap={16}>
              <Row justify="between" align="center">
                <Heading level={3} aria-live="polite">{selected.name} ({selected.symbol})</Heading>
                <Button variant="ghost" onPress={() => setSelected(null)}>Close</Button>
              </Row>
              <Stack direction="horizontal" gap={32}>
                <Stack gap={4}>
                  <Text variant="label">Atomic Number</Text>
                  <Text variant="bodyLarge">{selected.atomicNumber}</Text>
                </Stack>
                <Stack gap={4}>
                  <Text variant="label">Atomic Weight</Text>
                  <Text variant="bodyLarge">{selected.atomicWeight}</Text>
                </Stack>
                <Stack gap={4}>
                  <Text variant="label">Category</Text>
                  <Text variant="bodyLarge">{selected.category}</Text>
                </Stack>
              </Stack>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

