        <Box background="var(--ggui-color-surfaceVariant)" borderRadius="lg" style={{ flex: '1 1 400px', height: 400, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <Text weight="bold" color="var(--ggui-color-onSurfaceVariant)">{product.name}</Text>
        </Box>
        <Stack gap={16} style={{ flex: '1 1 300px' }}>
          <Heading level={2}>{product.name}</Heading>
          <Stack direction="horizontal" gap={8} align="center">
