              {[1, 2, 3, 4, 5].map((star) => (
                <Icon key={star} size={16} color="var(--ggui-color-warning-500, #f59e0b)">
                  <svg viewBox="0 0 24 24" fill={star <= (product.rating ?? 0) ? 'currentColor' : 'none'} stroke="currentColor" strokeWidth="2"><path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"/></svg>
                </Icon>
              ))}
            </Stack>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">({product.reviewCount} reviews)</Text>
          </Stack>
          <Text variant="3xl" weight="bold">{product.currency ?? '$'}{product.price?.toFixed(2)}</Text>
          <Badge variant={(product.stock ?? 0) === 0 ? 'error' : (product.stock ?? 0) < 5 ? 'warning' : 'success'}>
            {(product.stock ?? 0) === 0 ? 'Out of Stock' : (product.stock ?? 0) < 5 ? `Low Stock (${product.stock} left)` : `In Stock (${product.stock} left)`}
          </Badge>
          <Stack direction="horizontal" gap={12} align="end" style={{ marginTop: 16 }}>
            <FormField label="Quantity"><Input type="number" value={quantity.toString()} onChange={(v) => setQuantity(Math.max(1, Math.min(product.stock ?? 1, parseInt(v) || 1)))} disabled={isOutOfStock} /></FormField>
            <Button variant="primary" onClick={handleAdd} disabled={isOutOfStock} style={{ flexGrow: 1 }}>Add to Cart</Button>
          </Stack>
        </Stack>
      </Stack>
      <Spacer size={32} />
      <Tabs items={[
        { key: 'desc', label: 'Description', content: <Box paddingY={16}><Text variant="body">{product.description}</Text></Box> },
        { key: 'specs', label: 'Specifications', content: <Box paddingY={16}><Table striped columns={[{key: 'attribute', header: 'Attribute'}, {key: 'value', header: 'Value'}]} data={(product.specifications as any[]) || []} /></Box> },
        { key: 'reviews', label: 'Reviews', content: <CommentThread comments={(product.reviews as any[]) || []} onAddComment={() => {}} onReply={() => {}} onReaction={() => {}} /> }
      ]} />
    </Container>
  );
}

