import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[];
  roleOptions: string[];
  onComplete?: (data: Record<string, unknown>) => void; // Action: Complete Setup
}

function useComponent(props: Props) {
  const handleComplete = useCallback((data: Record<string, unknown>) => {
    props.onComplete?.(data);
  }, [props.onComplete]);

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile?.name || '',
    email: props.initialProfile?.email || '',
    avatar: props.initialProfile?.avatar || props.avatarOptions[0],
    role: props.initialProfile?.role || props.roleOptions[0],
    emailNotifications: props.initialProfile?.emailNotifications ?? true,
    theme: props.initialProfile?.theme || 'light',
  });

  const updateField = (field: string, value: any) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
  };

  const isValidEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const isCurrentStepValid = useMemo(() => {
    if (step === 1) return formData.name.trim().length > 0 && isValidEmail(formData.email);
    if (step === 2) return true; // Preferences step is currently valid
    if (step === 3) return true; // Review step is currently valid
    return true;
  }, [step, formData]);

  const steps = [
    { id: 1, title: 'Profile Setup' },
    { id: 2, title: 'Preferences' },
    { id: 3, title: 'Review & Confirm' }
  ];

  return {
    step,
    setStep,
    steps,
    formData,
    updateField,
    isCurrentStepValid,
    handleComplete
  };
}

export default function Component(props: Props) {
  const { step, setStep, steps, formData, updateField, isCurrentStepValid, handleComplete } = useComponent(props);

  return (
    <Container maxWidth="sm" padding="48px 16px">
      <Card padding={0} radius="xl" shadow="md" style={{ overflow: 'hidden' }}>
        <Box paddingX={32} paddingY={24} background="var(--ggui-color-primary-50)">
          <Stack gap={16}>
            <Row justify="between" align="center">
              <Heading level={2} color="var(--ggui-color-primary-900)">Onboarding</Heading>
              <Badge variant="primary" pill size="sm">{`Step ${step} / 3`}</Badge>
            </Row>
            <Progress value={(step / 3) * 100} variant="default" size="sm" />
          </Stack>
        </Box>
        <Box padding={32} style={{ minHeight: '360px' }}>
          <Stack gap={24}>
            <Heading level={3}>{steps[step - 1].title}</Heading>
            {step === 1 && (
              <Stack gap={16}>
                <FormField label="Full Name" required><Input value={formData.name} onChange={(v) => updateField('name', v)} placeholder="Jane Doe" /></FormField>
                <FormField label="Email Address" required error={!formData.email || isValidEmail(formData.email) ? '' : 'Invalid email address'}><Input type="email" value={formData.email} onChange={(v) => updateField('email', v)} placeholder="jane@example.com" /></FormField>
                <RadioGroup label="Select Avatar" value={formData.avatar} onChange={(v) => updateField('avatar', v)} options={props.avatarOptions.map(o => ({ value: o, label: o }))} direction="horizontal" />
              </Stack>
            )}
            {step === 2 && (
              <Stack gap={16}>
                <FormField label="Job Role"><Select value={formData.role} onChange={(v) => updateField('role', v)} options={props.roleOptions.map(o => ({ value: o, label: o }))} placeholder="Select your role" /></FormField>
                <Stack direction="horizontal" justify="between" align="center">
                  <Text variant="label">Email Notifications</Text>
                  <Toggle checked={formData.emailNotifications} onChange={(v) => updateField('emailNotifications', v)} />
                </Stack>
                <Stack direction="horizontal" justify="between" align="center">
                  <Text variant="label">Dark Mode</Text>
                  <Toggle checked={formData.theme === 'dark'} onChange={(v) => updateField('theme', v ? 'dark' : 'light')} />
                </Stack>
              </Stack>
            )}
            {step === 3 && (
              <Stack gap={16}>
                <Card padding={20} border radius="md" background="var(--ggui-color-surfaceVariant)">
                  <Stack gap={12}>
                    <Row justify="between"><Text variant="label">Name</Text><Text>{formData.name}</Text></Row>
                    <Divider />
                    <Row justify="between"><Text variant="label">Email</Text><Text>{formData.email}</Text></Row>
                    <Divider />
                    <Row justify="between"><Text variant="label">Role</Text><Text>{formData.role}</Text></Row>
                    <Divider />
                    <Row justify="between"><Text variant="label">Theme</Text><Text style={{ textTransform: 'capitalize' }}>{formData.theme}</Text></Row>
                  </Stack>
                </Card>
                <Alert variant="info" title="Final Step">Review your details before completing setup.</Alert>
              </Stack>
            )}
          </Stack>
        </Box>
        <Box padding={24} style={{ borderTop: '1px solid var(--ggui-color-outlineVariant)' }}>
          <Row justify="between" align="center">
            <Button variant="ghost" disabled={step === 1} onClick={() => setStep(s => s - 1)}>Back</Button>
            <Button variant="primary" disabled={!isCurrentStepValid} onClick={() => step < 3 ? setStep(s => s + 1) : handleComplete(formData)}>
              {step === 3 ? 'Complete Setup' : 'Next'}
            </Button>
          </Row>
        </Box>
      </Card>
    </Container>
  );
}
